$path = "F:\new\fishinggame\fishing_phy_log_20260309_200524.txt"; if (Test-Path $path) { Write-Host "Analyzing log file quietly..."; $lines = Get-Content $path; $flips = 0; $lastLen = [double]::NaN; $lastSign = 0; $frameCount = 0; foreach ($line in $lines) { if ($line -match "LineLen:([\d\.]+)") { $currentLen = [double]$matches[1]; if (-not [double]::IsNaN($lastLen)) { $diff = $currentLen - $lastLen; if ([Math]::Abs($diff) -gt 1e-6) { $sign = [Math]::Sign($diff); if ($lastSign -ne 0 -and $sign -ne $lastSign) { $flips++; } $lastSign = $sign; } } $lastLen = $currentLen; $frameCount++; } } Write-Host "----------------Result----------------"; Write-Host "Total Data Points: $frameCount"; Write-Host "Direction Flips: $flips"; if ($frameCount -gt 0) { $ratio = ($flips / $frameCount) * 100; Write-Host "Jitter Severity: $([Math]::Round($ratio, 2))%"; } } else { Write-Host "File not found." }
